function parse(data) {
  return typeof data === 'string' ? JSON.parse(data) : data;
}

function fuzzyFind(obj, keywords) {
  if (!obj) return 'N/A';
  for (const kw of keywords) {
    const foundKey = Object.keys(obj).find(k => k.toLowerCase().includes(kw.toLowerCase()));
    if (foundKey && obj[foundKey]) {
      return obj[foundKey];
    }
  }
  return 'N/A';
}

function findAllMessages(obj, results = []) {
  if (!obj || typeof obj !== 'object') return results;
  if (obj.Subject || obj.SubjectNoHTML || obj['@_Subject']) {
    results.push(obj);
    return results;
  }
  for (const key in obj) {
    if (typeof obj[key] === 'object') {
      findAllMessages(obj[key], results);
    }
  }
  return results;
}

function findGPADeep(obj) {
  if (!obj || typeof obj !== 'object') return null;
  if (Array.isArray(obj)) {
    for (const item of obj) {
      const found = findGPADeep(item);
      if (found) return found;
    }
    return null;
  }
  for (const key in obj) {
    const val = obj[key];
    if (val === null || val === undefined) continue;
    if (key.toLowerCase().includes('gpa')) {
      if (typeof val !== 'object') return val; 
      const leaf = val.Value || val['@_Value'] || val.Score || val['@_Score'] || val['#text'];
      if (leaf && typeof leaf !== 'object') return leaf;
      const innerFound = findGPADeep(val);
      if (innerFound) return innerFound;
    }
    if (typeof val === 'object') {
      const found = findGPADeep(val);
      if (found) return found;
    }
  }
  return null;
}

// Deep Object Explorer to dynamically locate district records regardless of XML wrapper shifts
function extractDistrictsDeep(obj) {
  if (!obj || typeof obj !== 'object') return [];
  if (Array.isArray(obj)) {
    let list = [];
    for (const item of obj) {
      list = list.concat(extractDistrictsDeep(item));
    }
    return list;
  }
  
  const url = obj.PvueURL || obj['@_PvueURL'] || obj.pvueurl || obj.PvueUrl;
  const name = obj.Name || obj['@_Name'] || obj.name || obj.DistrictName;
  if (url) {
    return [{ name: name || 'Unknown District Portal', url: String(url).trim() }];
  }

  let list = [];
  for (const key in obj) {
    if (typeof obj[key] === 'object') {
      list = list.concat(extractDistrictsDeep(obj[key]));
    }
  }
  return list;
}

function calculateTermGPAManually(grades) {
  if (!grades || grades.length === 0) return 'N/A';
  const gradeScale = { 'A': 4.0, 'B': 3.0, 'C': 2.0, 'D': 1.0, 'F': 0.0, 'E': 0.0 };
  let totalPoints = 0;
  let gradedClassesCount = 0;
  for (const course of grades) {
    if (!course.grade) continue;
    const baseLetter = course.grade.trim().charAt(0).toUpperCase();
    if (baseLetter in gradeScale) {
      totalPoints += gradeScale[baseLetter];
      gradedClassesCount++;
    }
  }
  return gradedClassesCount > 0 ? (totalPoints / gradedClassesCount).toFixed(2) : 'N/A';
}

